# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

# Connect to the database
conn = sqlite3.connect('permissions.db')
cursor = conn.cursor()

def check_permission(user_id, file_path):
    # Query the database to check user's permission
    cursor.execute("SELECT permission FROM permissions WHERE user_id = ? AND file_path = ?", (user_id, file_path))
    permission = cursor.fetchone()[0]

    # Return True if user has permission, False otherwise
    return permission == 'read'

def get_file_contents(user_id, file_path):
    # Check if user has permission to read the file
    if check_permission(user_id, file_path):
        # Open and return the file contents
        with open(file_path, 'r') as f:
            contents = f.read()
        return contents
    else:
        # Raise an error if user does not have permission
        raise PermissionError("User does not have permission to read this file.")